{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyMMhfwdagdVTiPkjK80bnvQ"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"markdown","source":["## **STEP 1 вҖ” Install All Required Dependencies** ##"],"metadata":{"id":"_7ZiTs6jE9x-"}},{"cell_type":"markdown","source":["###\n"," - langchain-core / langchain-community: core components and integrations.\n","\n"," - langchain-huggingface: connects Hugging Face pipelines to LangChain.\n","\n"," - faiss-cpu: vector database for semantic search.\n","\n"," - sentence-transformers: embedding models.\n","\n"," - PyPDF2: for reading PDFs.\n","\n"," - transformers / torch: for LLM models.\n","\n"," - gradio: for building the interactive web interface."],"metadata":{"id":"l2zCWLi4Fbce"}},{"cell_type":"code","execution_count":1,"metadata":{"id":"avjSg_XzD428","colab":{"base_uri":"https://localhost:8080/"},"executionInfo":{"status":"ok","timestamp":1762943633963,"user_tz":-330,"elapsed":44697,"user":{"displayName":"Parash Chinnu","userId":"17271847001559843057"}},"outputId":"d53e6777-8221-40c8-f545-bbd787be5edc"},"outputs":[{"output_type":"stream","name":"stdout","text":["\u001b[2K   \u001b[90mв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\u001b[0m \u001b[32m2.5/2.5 MB\u001b[0m \u001b[31m14.1 MB/s\u001b[0m eta \u001b[36m0:00:00\u001b[0m\n","\u001b[2K   \u001b[90mв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\u001b[0m \u001b[32m31.4/31.4 MB\u001b[0m \u001b[31m18.2 MB/s\u001b[0m eta \u001b[36m0:00:00\u001b[0m\n","\u001b[2K   \u001b[90mв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\u001b[0m \u001b[32m232.6/232.6 kB\u001b[0m \u001b[31m7.9 MB/s\u001b[0m eta \u001b[36m0:00:00\u001b[0m\n","\u001b[2K   \u001b[90mв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\u001b[0m \u001b[32m64.7/64.7 kB\u001b[0m \u001b[31m2.5 MB/s\u001b[0m eta \u001b[36m0:00:00\u001b[0m\n","\u001b[2K   \u001b[90mв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\u001b[0m \u001b[32m50.9/50.9 kB\u001b[0m \u001b[31m2.2 MB/s\u001b[0m eta \u001b[36m0:00:00\u001b[0m\n","\u001b[?25h\u001b[31mERROR: pip's dependency resolver does not currently take into account all the packages that are installed. This behaviour is the source of the following dependency conflicts.\n","google-colab 1.0.0 requires requests==2.32.4, but you have requests 2.32.5 which is incompatible.\u001b[0m\u001b[31m\n","\u001b[0m"]}],"source":["!pip install -q langchain langchain-core langchain-community langchain-huggingface faiss-cpu sentence-transformers PyPDF2 transformers torch gradio"]},{"cell_type":"markdown","source":["## **STEP 2 вҖ” Import Updated Libraries**"],"metadata":{"id":"wDTkg2ElFzNM"}},{"cell_type":"code","source":["import gradio as gr\n","import PyPDF2 as pp\n","import torch\n","# LangChain modules\n","from langchain.text_splitter import RecursiveCharacterTextSplitter\n","from langchain_community.embeddings import HuggingFaceEmbeddings\n","from langchain_community.vectorstores import FAISS\n","from langchain_huggingface import HuggingFacePipeline\n","from langchain_core.prompts import PromptTemplate\n","# Hugging Face utilities\n","from transformers import AutoTokenizer, AutoModelForCausalLM, pipeline"],"metadata":{"id":"d4O2KAp6F2jG","executionInfo":{"status":"ok","timestamp":1762943703667,"user_tz":-330,"elapsed":69691,"user":{"displayName":"Parash Chinnu","userId":"17271847001559843057"}}},"execution_count":2,"outputs":[]},{"cell_type":"markdown","source":["## **STEP 3 вҖ” PDF Text Extraction and Vector Database Creation**"],"metadata":{"id":"5uodyorXH5kN"}},{"cell_type":"code","source":["def process_pdf(pdf_file):\n","\n","  # blank string to hold extracted text\n","  text = \" \"\n","\n","  # Use PyPDF2 to extract text from pdf pages\n","  reader = pp.PdfReader(pdf_file.name)\n","  for page in reader.pages:\n","    extracted = page.extract_text()\n","    if extracted and extracted.strip():\n","      text += extracted\n","\n","  if not text:\n","    return None, None\n","\n","  # Split text into smaller overlapping chunks\n","  splitter = RecursiveCharacterTextSplitter(\n","      chunk_size = 500,\n","      chunk_overlap = 50\n","  )\n","  chunks = splitter.split_text(text)\n","\n","  # Create embeddings using a light model from Sentence-Transformers\n","  embedding_model = HuggingFaceEmbeddings(\n","      model_name = \"sentence-transformers/all-MiniLM-L6-V2\"\n","  )\n","\n","  # Store embeddings in FAISS vector database\n","  vectorstore = FAISS.from_texts(chunks, embedding_model)\n","\n","  return vectorstore, text"],"metadata":{"id":"x7K6RcbQGbdC","executionInfo":{"status":"ok","timestamp":1762943703683,"user_tz":-330,"elapsed":7,"user":{"displayName":"Parash Chinnu","userId":"17271847001559843057"}}},"execution_count":3,"outputs":[]},{"cell_type":"markdown","source":["## **STEP 4 вҖ” Load the Local LLM (Hugging Face model)**"],"metadata":{"id":"mxzoRWipLFm3"}},{"cell_type":"code","source":["def load_llm():\n","\n","\n","  model_name = \"distilgpt2\"\n","\n","  # Load the Tokenizer model\n","  tokenizer = AutoTokenizer.from_pretrained(model_name)\n","  model = AutoModelForCausalLM.from_pretrained(model_name)\n","\n","  # Build a text-generation pipeline\n","  generator = pipeline(\n","      \"text-generation\",\n","      model = model,\n","      tokenizer = tokenizer,\n","      max_new_tokens = 128,\n","      temperature = 0.3,\n","      top_p = 0.8\n","  )\n","\n","  # Wrap it in a LangChain LLM\n","  llm = HuggingFacePipeline(pipeline=generator)\n","  return llm"],"metadata":{"id":"JbxIUH9nLJGl","executionInfo":{"status":"ok","timestamp":1762944229427,"user_tz":-330,"elapsed":17,"user":{"displayName":"Parash Chinnu","userId":"17271847001559843057"}}},"execution_count":17,"outputs":[]},{"cell_type":"markdown","source":["## **STEP 5 вҖ” Core RAG Query Function (Retrieval + Generation)**"],"metadata":{"id":"lMYcWPLkMMVT"}},{"cell_type":"code","source":["def ask_question(pdf_file, question):\n","\n","  try:\n","    # if no file is uploaded, return a message\n","    if pdf_file is None:\n","      return \"вҡ пёҸ Please upload a PDF file first.\"\n","\n","    # 1пёҸвғЈ Build the vectorstore (extract text + embed)\n","    vectorstore, _ = process_pdf(pdf_file)\n","    retriever = vectorstore.as_retriever(search_kwargs={\"k\":3})\n","\n","    # 2пёҸвғЈ Load the LLM\n","    llm = load_llm()\n","\n","    # 3пёҸвғЈ Define the question-answering prompt\n","    prompt = PromptTemplate(\n","\n","        input_variables = [\"context\", \"question\"],\n","        template = (\n","\n","        \"\"\"\n","\n","        \"Context:\\n{context}\\n\\n\"\n","\n","        \"Question: {question}\\n\\n\"\n","\n","        \"Answer:\"\n","\n","        \"\"\"\n","      )\n","    )\n","\n","    # 4пёҸвғЈ Retrieve the most relevant text chunks\n","    docs = retriever.get_relevant_documents(question)\n","    context = \"\\n\".join([d.page_content for d in docs])\n","\n","    # 5пёҸвғЈ Format the final prompt and generate answer\n","    formatted_output = prompt.format(context=context, question=question)\n","    output = llm.invoke(formatted_output) # Corrected typo: formatted_prompt -> formatted_output\n","\n","    return output\n","\n","  except Exception as e:\n","    return f\"вқҢ Error: {str(e)}\"\n"],"metadata":{"id":"gNwa7T9hMG1W","executionInfo":{"status":"ok","timestamp":1762945040835,"user_tz":-330,"elapsed":70,"user":{"displayName":"Parash Chinnu","userId":"17271847001559843057"}}},"execution_count":39,"outputs":[]},{"cell_type":"markdown","source":["## **STEP 6 вҖ” Gradio User Interface (Frontend)**"],"metadata":{"id":"adqw2ZBDOpeJ"}},{"cell_type":"code","source":["with gr.Blocks(theme = gr.themes.Soft()) as rag_chatbot:\n","  # Title & Description\n","  gr.Markdown(\n","      \"\"\"\n","      # рҹ“ҳ Chat with Your PDF\n","      **Upload any PDF and ask questions about its content.**\n","      The model will retrieve relevant sections and answer contextually.\n","      \"\"\"\n","  )\n","\n","  # File upload row\n","  with gr.Row():\n","    pdf_file = gr.File(label = \"рҹ“Ӯ Upload a PDF\", file_types=[\".pdf\"] )\n","\n","  # User Input Row\n","  question = gr.Textbox(\n","        label = \" рҹ’¬ Ask a Question \",\n","        placeholder = \"e.g., What is the document about?\",\n","        lines = 1\n","  )\n","\n","  # Output field\n","  answer = gr.Textbox(\n","      label = \"рҹӨ– AI Answer\",\n","      placeholder = \"The model'response will appear here...\",\n","      lines = 8,\n","      max_lines = 12,\n","      interactive=False\n","  )\n","\n","  # Action Button\n","  submit_button = gr.Button(\"Ask\")\n","\n","  # Event : When the button is clicked -> Run the ask_question function\n","  submit_button.click(fn=ask_question, inputs=[pdf_file, question], outputs = answer)"],"metadata":{"id":"52GdDtjAOlNg","executionInfo":{"status":"ok","timestamp":1762945042773,"user_tz":-330,"elapsed":455,"user":{"displayName":"Parash Chinnu","userId":"17271847001559843057"}}},"execution_count":40,"outputs":[]},{"cell_type":"markdown","source":["## **STEP 7 вҖ” Launch the Gradio Interface**"],"metadata":{"id":"RLyClrXcRT3R"}},{"cell_type":"code","source":["rag_chatbot.launch(share=True)"],"metadata":{"colab":{"base_uri":"https://localhost:8080/","height":614},"id":"4j-DPHOtQ6IF","outputId":"e7bf7190-9cf3-4f80-dcb2-3cfbe2f33815","executionInfo":{"status":"ok","timestamp":1762945047397,"user_tz":-330,"elapsed":2382,"user":{"displayName":"Parash Chinnu","userId":"17271847001559843057"}}},"execution_count":41,"outputs":[{"output_type":"stream","name":"stdout","text":["Colab notebook detected. To show errors in colab notebook, set debug=True in launch()\n","* Running on public URL: https://54a0b7d7f0f02c41fc.gradio.live\n","\n","This share link expires in 1 week. For free permanent hosting and GPU upgrades, run `gradio deploy` from the terminal in the working directory to deploy to Hugging Face Spaces (https://huggingface.co/spaces)\n"]},{"output_type":"display_data","data":{"text/plain":["<IPython.core.display.HTML object>"],"text/html":["<div><iframe src=\"https://54a0b7d7f0f02c41fc.gradio.live\" width=\"100%\" height=\"500\" allow=\"autoplay; camera; microphone; clipboard-read; clipboard-write;\" frameborder=\"0\" allowfullscreen></iframe></div>"]},"metadata":{}},{"output_type":"execute_result","data":{"text/plain":[]},"metadata":{},"execution_count":41}]},{"cell_type":"code","source":[],"metadata":{"id":"TyRCaqhmVOVX","executionInfo":{"status":"ok","timestamp":1762944936280,"user_tz":-330,"elapsed":7,"user":{"displayName":"Parash Chinnu","userId":"17271847001559843057"}}},"execution_count":38,"outputs":[]}]}